import React, { useEffect, useState } from 'react';
import { useForm } from 'react-hook-form';
import { useAuth } from '../context/AuthContext';
import api from '../api';
import './Profile.css';

const BLOOD_GROUPS = ['A+', 'A-', 'B+', 'B-', 'AB+', 'AB-', 'O+', 'O-'];

export default function Profile() {
  const { user, updateUser } = useAuth();
  const { register, handleSubmit, setValue, watch, formState: { errors } } = useForm();
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const [profileData, setProfileData] = useState(null);

  const available = watch('available');

  useEffect(() => {
    api.get('/profile').then(res => {
      const { user: u, donor: d } = res.data;
      setProfileData(res.data);
      setValue('name', u.name);
      setValue('phone', u.phone || '');
      setValue('location', u.location || '');
      if (d) {
        setValue('blood_group', d.blood_group);
        setValue('last_donation_date', d.last_donation_date || '');
        setValue('available', d.available === 1);
        setValue('health_eligible', d.health_eligible === 1);
        setValue('latitude', d.latitude || '');
        setValue('longitude', d.longitude || '');
      }
    }).catch(() => setError('Failed to load profile.'))
    .finally(() => setLoading(false));
  }, [setValue]);

  const onSubmit = async (data) => {
    setError(''); setSuccess('');
    setSaving(true);
    try {
      const payload = {
        name: data.name,
        phone: data.phone,
        location: data.location,
      };
      if (data.password) payload.password = data.password;
      if (profileData?.donor) {
        payload.blood_group = data.blood_group;
        payload.last_donation_date = data.last_donation_date;
        payload.available = data.available ? 1 : 0;
        payload.health_eligible = data.health_eligible ? 1 : 0;
        payload.latitude = data.latitude ? parseFloat(data.latitude) : null;
        payload.longitude = data.longitude ? parseFloat(data.longitude) : null;
      }
      const res = await api.put('/update-profile', payload);
      updateUser({ ...user, name: res.data.user.name, phone: res.data.user.phone, location: res.data.user.location });
      setSuccess('Profile updated successfully!');
    } catch (err) {
      setError(err.response?.data?.error || 'Failed to update profile.');
    } finally {
      setSaving(false);
    }
  };

  if (loading) return (
    <div className="page-container" style={{ textAlign: 'center', paddingTop: '4rem' }}>
      <span className="spinner" style={{ width: 36, height: 36 }} />
    </div>
  );

  return (
    <div className="page-container">
      <h1 className="page-title">👤 My Profile</h1>

      <div className="profile-layout">
        {/* Info card */}
        <div className="profile-info card">
          <div className="profile-avatar">{user?.name?.[0]?.toUpperCase()}</div>
          <h2 className="profile-name">{user?.name}</h2>
          <span className="profile-role">{user?.role}</span>
          <p className="profile-email">{user?.email}</p>
          {profileData?.donor && (
            <div className="profile-donor-badge">
              <span className="blood-group-badge">{profileData.donor.blood_group}</span>
              <span className={`badge ${profileData.donor.available ? 'badge-green' : 'badge-gray'}`}>
                {profileData.donor.available ? 'Available' : 'Unavailable'}
              </span>
            </div>
          )}
        </div>

        {/* Edit form */}
        <div className="card" style={{ flex: 1 }}>
          <h2 className="section-title">Edit Profile</h2>

          {error   && <div className="alert alert-error">{error}</div>}
          {success && <div className="alert alert-success">{success}</div>}

          <form onSubmit={handleSubmit(onSubmit)}>
            <div className="grid-2">
              <div className="form-group">
                <label>Full Name</label>
                <input {...register('name', { required: 'Name is required' })} />
                {errors.name && <span className="error">{errors.name.message}</span>}
              </div>
              <div className="form-group">
                <label>Phone Number</label>
                <input placeholder="+1 555 000 0000" {...register('phone')} />
              </div>
              <div className="form-group">
                <label>Location / City</label>
                <input placeholder="e.g. New York, NY" {...register('location')} />
              </div>
              <div className="form-group">
                <label>New Password (leave blank to keep current)</label>
                <input type="password" placeholder="••••••••" {...register('password', { minLength: { value: 6, message: 'Min 6 characters' } })} />
                {errors.password && <span className="error">{errors.password.message}</span>}
              </div>
            </div>

            {profileData?.donor && (
              <>
                <hr className="divider" />
                <h3 className="subsection-title">Donor Details</h3>
                <div className="grid-2">
                  <div className="form-group">
                    <label>Blood Group</label>
                    <select {...register('blood_group')}>
                      {BLOOD_GROUPS.map(g => <option key={g} value={g}>{g}</option>)}
                    </select>
                  </div>
                  <div className="form-group">
                    <label>Last Donation Date</label>
                    <input type="date" {...register('last_donation_date')} max={new Date().toISOString().split('T')[0]} />
                  </div>
                  <div className="form-group">
                    <label>Latitude</label>
                    <input type="number" step="any" {...register('latitude')} />
                  </div>
                  <div className="form-group">
                    <label>Longitude</label>
                    <input type="number" step="any" {...register('longitude')} />
                  </div>
                </div>

                <div className="toggle-section">
                  <div className="toggle-row">
                    <label className="toggle">
                      <input type="checkbox" {...register('available')} />
                      <span className="toggle-slider" />
                    </label>
                    <div>
                      <span className="toggle-label">Available to Donate</span>
                      <span className="toggle-desc">{available ? 'Currently available' : 'Not available'}</span>
                    </div>
                  </div>
                  <div className="toggle-row">
                    <label className="toggle">
                      <input type="checkbox" {...register('health_eligible')} />
                      <span className="toggle-slider" />
                    </label>
                    <div>
                      <span className="toggle-label">Health Eligible</span>
                    </div>
                  </div>
                </div>
              </>
            )}

            <div className="form-actions">
              <button type="submit" className="btn btn-primary" disabled={saving}>
                {saving ? <span className="spinner" /> : 'Save Changes'}
              </button>
            </div>
          </form>
        </div>
      </div>
    </div>
  );
}
